## `ToastProvider`  [](https://www.sanity.io/ui/docs/component/toast#toast-provider)  

In order to use toasts, you need to wrap your application in the `<ToastProvider />`:

```
import {ToastProvider} from '@sanity/ui'

export function App () {
  return <ToastProvider>[...]</ToastProvider>
}
```

## `useToast`  [](https://www.sanity.io/ui/docs/component/toast#use-toast)  

When a component is wrapped in the `<ToastProvider />`, the hook to push toasts to the stack of toasts is available:

```
import {Button, useToast} from '@sanity/ui'

function Section () {
  const toast = useToast()

  return (
    <Button
      icon="rocket"
      onClick={
        () => toast.push({
          title: 'An important message'
        })
      }
    />
  )
}
```

# useGlobalKeyDown | Sanity UI

```
import {useGlobalKeyDown} from '@sanity/ui'
import isHotkey from 'is-hotkey'
import React, {useCallback} from 'react'

const isSaveHotkey = isHotkey('mod+s')

function App () {
  const handleGlobalKeyDown = useCallback(
    (event: KeyboardEvent) => {
      if (isSaveHotkey(event)) {
        event.preventDefault()
        // Sanity autosaves your work!
      }
    },
    []
  )

  useGlobalKeyDown(handleGlobalKeyDown)

  return <>...</>
}
```

# usePrefersDark

```
import {
  Card,
  studioTheme,
  ThemeProvider,
  usePrefersDark
} from '@sanity/ui'
import React from 'react'

function App () {
  // This value will change when the system switches
  // between dark and light scheme.
  const prefersDark = usePrefersDark()

  // The theme system supports either "dark" or "light"
  const scheme = prefersDark ? 'dark' : 'light'

  return (
    <ThemeProvider scheme={scheme} theme={studioTheme}>
      <Card>...</Card>
    </ThemeProvider>
  )
}
```

